import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import './QuizSelectionPage.css';

const QuizSelectionPage = () => {
    const [selectedQuiz, setSelectedQuiz] = useState(null);
    const navigate = useNavigate();

    // Quiz categories with their details
    const quizCategories = [
        {
            id: 'caries',
            title: 'Кариес зубов',
            description: 'Тест на знание этиологии, патогенеза, классификации и методов лечения кариеса.',
            icon: 'tooth-icon.svg',
            questionsCount: 10,
            difficulty: 'Средний'
        },
        {
            id: 'periodontitis',
            title: 'Заболевания пародонта',
            description: 'Вопросы о диагностике и лечении гингивита, пародонтита и других заболеваний пародонта.',
            icon: 'gum-icon.svg',
            questionsCount: 8,
            difficulty: 'Сложный'
        },
        {
            id: 'prosthetics',
            title: 'Ортопедическая стоматология',
            description: 'Вопросы о методах протезирования, материалах и конструкциях зубных протезов.',
            icon: 'crown-icon.svg',
            questionsCount: 12,
            difficulty: 'Средний'
        },
        {
            id: 'anatomy',
            title: 'Анатомия зубов',
            description: 'Тест по анатомии зубов, их строению и классификации.',
            icon: 'jaw-icon.svg',
            questionsCount: 7,
            difficulty: 'Легкий'
        },
        {
            id: 'surgery',
            title: 'Хирургическая стоматология',
            description: 'Вопросы о хирургических вмешательствах, удалении зубов и имплантации.',
            icon: 'surgery-icon.svg',
            questionsCount: 9,
            difficulty: 'Сложный'
        }
    ];

    // Handle quiz selection
    const handleQuizSelect = (quizId) => {
        setSelectedQuiz(quizId);
    };

    // Start the selected quiz
    const startQuiz = () => {
        if (selectedQuiz) {
            navigate(`/quiz/${selectedQuiz}`);
        }
    };

    return (
        <div className="quiz-selection-container">
            <header className="selection-header">
                <h1>Стоматологические тесты</h1>
                <p>Выберите тему теста для проверки своих знаний</p>
            </header>

            <div className="quiz-categories">
                {quizCategories.map((category) => (
                    <div
                        key={category.id}
                        className={`quiz-card ${selectedQuiz === category.id ? 'selected' : ''}`}
                        onClick={() => handleQuizSelect(category.id)}
                    >
                        <div className="quiz-card-header">
                            <div className="quiz-icon">
                                <img src={`/icons/${category.icon}`} alt={category.title} />
                            </div>
                            <h2>{category.title}</h2>
                        </div>

                        <div className="quiz-description">
                            <p>{category.description}</p>
                        </div>

                        <div className="quiz-meta">
              <span className="questions-count">
                <i className="question-icon"></i> {category.questionsCount} вопросов
              </span>
                            <span className="difficulty">
                Сложность: {category.difficulty}
              </span>
                        </div>
                    </div>
                ))}
            </div>

            <div className="quiz-selection-footer">
                <button
                    className="start-quiz-button"
                    disabled={!selectedQuiz}
                    onClick={startQuiz}
                >
                    {selectedQuiz ? 'Начать тест' : 'Выберите тест'}
                </button>
            </div>
        </div>
    );
};

export default QuizSelectionPage;
